function downloadFile(key, filename) {
  const b64 = _F[key];
  if (!b64) return;
  const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0)); const html = new TextDecoder("utf-8").decode(bytes);
  const blob = new Blob([html], {type:'text/html;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; 
  document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

function previewFile(key) {
  const b64 = _F[key];
  if (!b64) return '';
  const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0)); return new TextDecoder("utf-8").decode(bytes);
}

// Expand metadata
const SEQUENCES = _M.map(m => ({
  id: m[0], niveau: m[1], titre: m[2], description: m[3], nbFiles: m[4],
  seances: m[5].map(s => ({
    num: s[0], titre: s[1], type: s[2], contenu: s[3],
    files: s[4].map(f => ({ label: f[0], icon: f[1], key: f[2], filename: f[3] }))
  })),
  resources: m[6].map(r => ({ label: r[0], icon: r[1], key: r[2], filename: r[3] }))
}));


